INSERT INTO `room_type` VALUES (1,'单人套房',0,4000.00,'宽敞舒适的套房，配备独立卫生间和基本生活设施，满足独自居住的需求，提供私密性和舒适度','https://yjy-slwl-oss.oss-cn-hangzhou.aliyuncs.com/e2f1031b-e23e-4379-95d4-ce8fe382f58f.png',1,'2023-09-26 15:57:50','2023-09-26 15:57:50',1671403256519078153,NULL,NULL),(2,'双人套房',0,6000.00,'适合夫妻或朋友两人居住的套房，设有独立卫生间和基本生活设施，提供共享空间和私密性','https://yjy-slwl-oss.oss-cn-hangzhou.aliyuncs.com/ff84c185-2e28-431c-951d-d004cc2d5bdc.png',1,'2023-09-26 15:58:51','2023-09-26 15:58:51',1671403256519078153,NULL,NULL),(3,'豪华单人间',0,3000.00,'豪华装修的单人房间，提供舒适的居住环境和高品质的服务，设计精美，配备独立卫生间和必需设施','https://yjy-slwl-oss.oss-cn-hangzhou.aliyuncs.com/d803832c-5b93-4cae-ba95-aeb52ab0c5e0.png',1,'2023-09-26 15:59:33','2023-09-26 15:59:33',1671403256519078153,NULL,NULL),(4,'豪华双人间',0,4500.00,'精心装修的双人房间，提供舒适和豪华的居住环境，配备独立卫生间和高品质的家具','https://yjy-slwl-oss.oss-cn-hangzhou.aliyuncs.com/c3522da7-4c5c-48d2-94f9-9f0b95a048d2.png',1,'2023-09-26 16:00:03','2023-09-26 16:00:03',1671403256519078153,NULL,NULL),(5,'普通单人间',0,2000.00,'简洁实用的单人房间，提供基本的居住设施和舒适度，适合独自居住的老年人，提供相对经济实惠的居住选择','https://yjy-slwl-oss.oss-cn-hangzhou.aliyuncs.com/1a330b1c-b0a1-463d-8d9a-221ef17c314f.png',1,'2023-09-26 16:00:27','2023-09-26 16:00:27',1671403256519078153,NULL,NULL),(6,'普通双人间',0,3500.00,'标准的双人房间，提供基本的舒适居住环境。配备共用卫生间和必要的家具','https://yjy-slwl-oss.oss-cn-hangzhou.aliyuncs.com/6c462b11-2499-4bd3-8daf-2db39422c6c0.png',1,'2023-09-26 16:00:55','2023-09-26 16:00:55',1671403256519078153,NULL,NULL),(7,'特护房',0,8000.00,'专为特殊护理需求设计的房间，配备个性化护理设施和服务，提供特别关注、监测和护理','https://yjy-slwl-oss.oss-cn-hangzhou.aliyuncs.com/b61292a3-1702-47b7-bb80-cdd33280839d.png',1,'2023-09-26 16:01:32','2023-09-26 16:01:32',1671403256519078153,NULL,NULL);
