--
-- Table structure for table `trading`
--

DROP TABLE IF EXISTS `trading`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `trading` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `product_order_no` bigint unsigned DEFAULT NULL COMMENT '业务系统订单号',
  `trading_order_no` bigint DEFAULT NULL COMMENT '交易系统订单号【对于三方来说：商户订单】',
  `trading_channel` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '支付渠道【支付宝、微信、现金、免单挂账】',
  `trading_type` varchar(22) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '交易类型【1月度费用 2服务费用】',
  `trading_state` int DEFAULT NULL COMMENT '交易单状态【1-待付款,2-付款中,3-付款失败,4-已结算,5-取消订单,6-免单,7-挂账】',
  `payee_name` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '收款人姓名',
  `payee_id` bigint DEFAULT NULL COMMENT '收款人账户ID',
  `payer_name` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '付款人姓名',
  `payer_id` bigint DEFAULT NULL COMMENT '付款人Id',
  `trading_amount` decimal(22,2) DEFAULT NULL COMMENT '交易金额，单位：元',
  `refund` decimal(12,2) unsigned zerofill DEFAULT '0000000000.00' COMMENT '退款金额【付款后，单位：元',
  `is_refund` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '是否有退款：YES，NO',
  `result_code` varchar(80) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '第三方交易返回编码【最终确认交易结果】',
  `result_msg` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '第三方交易返回提示消息【最终确认交易信息】',
  `result_json` varchar(2000) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '第三方交易返回信息json【分析交易最终信息】',
  `place_order_code` varchar(80) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '统一下单返回编码',
  `place_order_msg` varchar(255) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '统一下单返回信息',
  `place_order_json` text CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci COMMENT '统一下单返回信息json【用于生产二维码、Android ios唤醒支付等】',
  `enterprise_id` bigint DEFAULT NULL COMMENT '商户号',
  `memo` varchar(150) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '备注【订单门店，桌台信息】',
  `qr_code` text CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci COMMENT '二维码base64数据',
  `open_id` varchar(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'open_id标识',
  `enable_flag` varchar(10) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '是否有效',
  `create_time` datetime NOT NULL COMMENT '创建时间',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  `create_by` bigint DEFAULT NULL COMMENT '创建人id',
  `update_by` bigint DEFAULT NULL COMMENT '更新人id',
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '备注',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `index_order_id` (`product_order_no`) USING BTREE,
  KEY `index_tpptrs` (`trading_channel`) USING BTREE,
  KEY `trading_order_no` (`trading_order_no`) USING BTREE,
  KEY `trading_state` (`trading_state`) USING BTREE,
  KEY `create_time` (`create_time`) USING BTREE,
  KEY `enable_flag` (`enable_flag`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=593 DEFAULT CHARSET=utf8mb3 ROW_FORMAT=DYNAMIC COMMENT='交易订单表';
/*!40101 SET character_set_client = @saved_cs_client */;

